#include <bits/stdc++.h>
using namespace std;
int t,n,a;
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        int num=0;
        for(int i=1;i<=n;i++){
            scanf("%d",&a);
            num^=a;
        }
        if(num)
            printf("Yes\n");
        else
            printf("No\n");
    }
    return 0;
}
